import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend, CartesianGrid } from 'recharts';
import { useNavigate } from 'react-router-dom';

const Icons = {
  Users: () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/>
      <path d="M23 21v-2a4 4 0 0 0-3-3.87M16 3.13a4 4 0 0 1 0 7.75"/>
    </svg>
  ),
  Bus: () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M19 17h2a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2H3a2 2 0 0 0-2 2v8a2 2 0 0 0 2 2h2"/>
      <circle cx="7" cy="17" r="2"/><circle cx="17" cy="17" r="2"/><path d="M5 17h10M13 5v8M1 9h22M5 5v4"/>
    </svg>
  ),
  Check: () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <polyline points="20 6 9 17 4 12"/>
    </svg>
  ),
  Clock: () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/>
    </svg>
  ),
  Alert: () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/>
    </svg>
  ),
  Trending: () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <polyline points="23 6 13.5 15.5 8.5 10.5 1 18"/><polyline points="17 6 23 6 23 12"/>
    </svg>
  )
};

export default function AdminDashboard() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    axios.get('/fees/dashboard').then(r => setStats(r.data)).catch(console.error).finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="loading-screen" style={{ height: 300 }}><div className="spinner" /></div>;
  if (!stats) return <div className="alert alert-error">⚠️ Failed to load system analytics.</div>;

  const fmt = n => `₹${Number(n || 0).toLocaleString('en-IN')}`;
  const total = (stats.summary?.collected || 0) + (stats.summary?.pending || 0) + (stats.summary?.overdue || 0);
  const collectionRate = total > 0 ? Math.round((stats.summary.collected / total) * 100) : 0;

  const pieData = [
    { name: 'Collected', value: stats.summary?.collected || 0, color: '#16a34a' },
    { name: 'Pending', value: stats.summary?.pending || 0, color: '#f97316' },
    { name: 'Overdue', value: stats.summary?.overdue || 0, color: '#dc2626' },
  ].filter(d => d.value > 0);

  const routeBarData = (stats.routeStats || []).map(r => ({
    name: r.route?.routeNumber || 'N/A',
    collected: parseFloat(r.dataValues?.totalCollected || 0),
    total: parseFloat(r.dataValues?.totalAmount || 0),
  })).slice(0, 8);

  const statCards = [
    { label: 'Total Students', value: stats.totalStudents, icon: <Icons.Users />, cls: 'blue', sub: 'Enrolled profiles', action: () => navigate('/admin/students') },
    { label: 'Active Routes', value: stats.totalRoutes, icon: <Icons.Bus />, cls: 'purple', sub: 'Running daily buses', action: () => navigate('/admin/routes') },
    { label: 'Fees Collected', value: fmt(stats.summary?.collected), icon: <Icons.Check />, cls: 'green', sub: `${stats.paidCount || 0} students paid`, action: () => navigate('/admin/fees') },
    { label: 'Pending Dues', value: fmt(stats.summary?.pending), icon: <Icons.Clock />, cls: 'yellow', sub: `${stats.pendingCount || 0} upcoming payments`, action: () => navigate('/admin/upcoming') },
    { label: 'Overdue Fees', value: fmt(stats.summary?.overdue), icon: <Icons.Alert />, cls: 'red', sub: 'Immediate action required', action: () => navigate('/admin/overdue') },
    { label: 'Collection Efficiency', value: `${collectionRate}%`, icon: <Icons.Trending />, cls: '', sub: stats.currentMonth },
  ];

  return (
    <div>
      {/* Welcome Banner */}
      <div style={{
        background: 'linear-gradient(135deg, #0f172a 0%, #064e3b 100%)',
        borderRadius: '24px', padding: '40px', marginBottom: 32,
        color: 'white', display: 'flex', justifyContent: 'space-between', alignItems: 'center',
        flexWrap: 'wrap', gap: 24, boxShadow: 'var(--shadow-xl)', position: 'relative', overflow: 'hidden'
      }}>
        <div style={{ position: 'relative', zIndex: 1 }}>
          <div style={{ fontSize: 13, fontWeight: 700, opacity: 0.6, textTransform: 'uppercase', letterSpacing: 2, marginBottom: 12 }}>System Overview Console</div>
          <h2 style={{ fontSize: 32, fontWeight: 800, color: 'white', marginBottom: 8 }}>Kongu Engineering College</h2>
          <p style={{ fontSize: 16, opacity: 0.8 }}>Administering Transportation & Fees Services · <strong>{stats.currentMonth}</strong></p>
        </div>
        <div style={{ display: 'flex', gap: 12, position: 'relative', zIndex: 1 }}>
          <button className="btn btn-primary" style={{ background: 'white', color: 'var(--primary)' }} onClick={() => navigate('/admin/fees')}>
            Manage Fees
          </button>
          <button className="btn" style={{ background: 'rgba(255,255,255,0.1)', color: 'white', border: '1px solid rgba(255,255,255,0.2)' }} onClick={() => navigate('/admin/students')}>
            Student Registry
          </button>
        </div>
        {/* Glow */}
        <div style={{ 
          position: 'absolute', left: '20%', top: '-50%', width: '400px', height: '400px', 
          background: 'var(--secondary)', filter: 'blur(100px)', opacity: 0.15, pointerEvents: 'none' 
        }} />
      </div>

      {/* Stats Cards */}
      <div className="stats-grid">
        {statCards.map((s, i) => (
          <div
            key={i}
            className={`stat-card ${s.cls}`}
            onClick={s.action}
            style={{ cursor: s.action ? 'pointer' : 'default' }}
          >
            <div className="stat-icon">{s.icon}</div>
            <div className="stat-label">{s.label}</div>
            <div className="stat-value">{s.value}</div>
            <div className="stat-sub">{s.sub}</div>
            {s.label.includes('Collection') && (
              <div className="progress-bar" style={{ marginTop: 12 }}>
                <div className={`progress-fill ${collectionRate > 80 ? 'progress-green' : collectionRate > 40 ? 'progress-yellow' : 'progress-red'}`} style={{ width: `${collectionRate}%` }} />
              </div>
            )}
          </div>
        ))}
      </div>

      {/* Quick Actions Integration */}
      <div style={{ marginBottom: 32 }}>
        <h3 style={{ fontSize: 14, fontWeight: 800, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: 1, marginBottom: 16 }}>Rapid Access</h3>
        <div className="quick-actions">
           {[
            { icon: '👥', label: 'Student List', to: '/admin/students' },
            { icon: '⚡', label: 'Gen Fees', to: '/admin/fees' },
            { icon: '🗓️', label: 'Schedules', to: '/admin/schedules' },
            { icon: '🗺️', label: 'Route Config', to: '/admin/routes' },
            { icon: '⚠️', label: 'Overdue Dues', to: '/admin/overdue' },
            { icon: '👤', label: 'My Profile', to: '/admin/profile' },
          ].map(a => (
            <div key={a.label} className="quick-action" onClick={() => navigate(a.to)}>
              <span className="icon">{a.icon}</span>
              <span>{a.label}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Analytics Visuals */}
      <div className="charts-grid">
        <div className="card">
          <div className="card-header">
            <h3 className="card-title"><span>📊</span> Monthly Recovery Rate</h3>
          </div>
          <div style={{ padding: '24px 0' }}>
            <ResponsiveContainer width="100%" height={260}>
              <PieChart>
                <Pie 
                  data={pieData} 
                  cx="50%" cy="50%" 
                  innerRadius={65} outerRadius={95} 
                  paddingAngle={5} 
                  dataKey="value"
                  animationBegin={0}
                  animationDuration={1200}
                >
                  {pieData.map((e, i) => <Cell key={i} fill={e.color} />)}
                </Pie>
                <Tooltip formatter={v => fmt(v)} />
                <Legend iconType="circle" />
              </PieChart>
            </ResponsiveContainer>
            <div style={{ textAlign: 'center', marginTop: -20 }}>
              <div style={{ fontSize: 32, fontWeight: 900, color: collectionRate > 80 ? 'var(--success)' : 'var(--accent)' }}>
                {collectionRate}%
              </div>
              <div style={{ fontSize: 12, fontWeight: 700, opacity: 0.5, textTransform: 'uppercase' }}>Efficiency</div>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="card-header">
            <h3 className="card-title"><span>🚌</span> Collection by Route</h3>
          </div>
          <div style={{ padding: '24px 16px 12px 0' }}>
            <ResponsiveContainer width="100%" height={320}>
              <BarChart data={routeBarData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 12, fontWeight: 600 }} />
                <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 12 }} />
                <Tooltip cursor={{ fill: 'transparent' }} formatter={v => fmt(v)} />
                <Bar dataKey="collected" fill="var(--primary)" radius={[4, 4, 0, 0]} barSize={24} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Detailed Routes Table */}
      <div className="card">
        <div className="card-header">
          <h3 className="card-title">🚌 Detailed Route Performance — {stats.currentMonth}</h3>
          <button className="btn btn-outline btn-sm" onClick={() => navigate('/admin/routes')}>Manage Routes</button>
        </div>
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Route</th>
                <th>Target Amount</th>
                <th>Collected</th>
                <th>Gap</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {(stats.routeStats || []).map((r, i) => {
                const target = parseFloat(r.dataValues?.totalAmount || 0);
                const col = parseFloat(r.dataValues?.totalCollected || 0);
                const gap = target - col;
                const perc = target > 0 ? Math.round((col / target) * 100) : 0;

                return (
                  <tr key={i}>
                    <td>
                      <div style={{ fontWeight: 700 }}>Route {r.route?.routeNumber}</div>
                      <div style={{ fontSize: 11, opacity: 0.6 }}>{r.route?.routeName}</div>
                    </td>
                    <td>{fmt(target)}</td>
                    <td style={{ color: 'var(--success)', fontWeight: 700 }}>{fmt(col)}</td>
                    <td style={{ color: gap > 0 ? 'var(--danger)' : 'var(--text-muted)' }}>{fmt(gap)}</td>
                    <td>
                      <div className="progress-bar" style={{ width: 100, display: 'inline-block', verticalAlign: 'middle', marginRight: 10 }}>
                        <div className="progress-fill progress-green" style={{ width: `${perc}%` }} />
                      </div>
                      <span style={{ fontSize: 12, fontWeight: 700 }}>{perc}%</span>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
const KEC_NAME = 'Kongu Engineering College';
